#include <stdio.h>
#include <poll.h>
#include <unistd.h>
#include <string.h>
int main(void) {
    int pipe1[2], pipe2[2];
    pipe(pipe1);
    pipe(pipe2);
    write(pipe1[1], "data1", 5);
    close(pipe1[1]);
    struct pollfd fds[2];
    fds[0].fd = pipe1[0];
    fds[0].events = POLLIN;
    fds[1].fd = pipe2[0];
    fds[1].events = POLLIN;
    int ready = poll(fds, 2, 0);
    printf("Ready: %d\n", ready);
    printf("pipe1 readable: %d\n", (fds[0].revents & POLLIN) != 0);
    printf("pipe2 readable: %d\n", (fds[1].revents & POLLIN) != 0);
    if (fds[0].revents & POLLIN) {
        char buf[16];
        ssize_t n = read(pipe1[0], buf, sizeof(buf) - 1);
        buf[n] = '\0';
        printf("pipe1 data: %s\n", buf);
    }
    close(pipe1[0]);
    close(pipe2[0]);
    close(pipe2[1]);
    return 0;
}

